import{_ as e}from"./chunks/tax-1.D_QI6uE7.js";import{_ as p,C as l,c as t,o as i,j as a,G as r,a2 as d,a as c}from"./chunks/framework.DrNAj9nU.js";const f=JSON.parse('{"title":"个人所得税已缴税额详解","description":"","frontmatter":{},"headers":[],"relativePath":"column/CommonSense/生活常识/个人所得税已缴税额详解.md","filePath":"column/CommonSense/生活常识/个人所得税已缴税额详解.md","lastUpdated":1773305038000}'),b={name:"column/CommonSense/生活常识/个人所得税已缴税额详解.md"};function o(u,s,h,m,g,v){const n=l("ArticleMetadata");return i(),t("div",null,[s[0]||(s[0]=a("h1",{id:"个人所得税已缴税额详解",tabindex:"-1"},[c("个人所得税已缴税额详解 "),a("a",{class:"header-anchor",href:"#个人所得税已缴税额详解","aria-label":'Permalink to "个人所得税已缴税额详解"'},"​")],-1)),r(n),s[1]||(s[1]=d('<nav class="table-of-contents"><ul><li><a href="#一、综合所得包含哪些收入">一、综合所得包含哪些收入</a></li><li><a href="#二、收入合计">二、收入合计</a></li><li><a href="#三、费用合计">三、费用合计</a></li><li><a href="#四、免税收入">四、免税收入</a></li><li><a href="#五、减除费用">五、减除费用</a></li><li><a href="#六、专项扣除合计">六、专项扣除合计</a></li><li><a href="#七、专项附加扣除合计">七、专项附加扣除合计</a></li><li><a href="#八、其他扣除合计">八、其他扣除合计</a></li><li><a href="#九、准予扣除的捐赠额">九、准予扣除的捐赠额</a></li><li><a href="#十、应纳税所得额">十、应纳税所得额</a></li><li><a href="#十一、应纳所得税额-应纳税额">十一、应纳所得税额(应纳税额)</a></li><li><a href="#十二、减免税额">十二、减免税额</a></li><li><a href="#十三、已缴税额-全年已预缴的个人所得税">十三、已缴税额（全年已预缴的个人所得税）</a><ul><li><a href="#每月计算公式">每月计算公式</a></li><li><a href="#为什么会-跳档">为什么会&quot;跳档&quot;？</a></li><li><a href="#全年流程图">全年流程图</a></li></ul></li><li><a href="#十四、最终退税或补税">十四、最终退税或补税</a><ul><li><a href="#情况1-多缴税">情况1：多缴税</a></li><li><a href="#情况2-少缴税">情况2：少缴税</a></li></ul></li><li><a href="#十五、完整计算流程图">十五、完整计算流程图</a></li></ul></nav><div style="text-align:center;"><img src="'+e+`" alt="税" style="width:400px;display:inline-block;"></div><p><strong>综合所得年度汇算申报明细</strong> 是中国个人所得税年度汇算清缴时的一张核心计算表。 它会把你 <strong>一年所有综合所得 + 各种扣除项 + 已缴税额</strong> 汇总，然后计算：</p><ul><li>是否需要 <strong>补税</strong></li><li>是否可以 <strong>退税</strong></li></ul><p>这个申报一般在每年 <strong>3月1日–6月30日</strong> 通过 个人所得税APP 完成。</p><p>下面把你列出的每一项 <strong>逐个解释清楚，并给出计算逻辑</strong>。</p><h2 id="一、综合所得包含哪些收入" tabindex="-1">一、综合所得包含哪些收入 <a class="header-anchor" href="#一、综合所得包含哪些收入" aria-label="Permalink to &quot;一、综合所得包含哪些收入&quot;">​</a></h2><p>在中国个人所得税体系里，综合所得包括四类收入：</p><ul><li>1️⃣ 工资薪金</li></ul><p>上班族按月领取的固定收入,单位每月代扣个税，采用累计预扣法,3%-45%累进税率</p><ul><li>2️⃣ 劳务报酬</li></ul><p>自由接单如兼职、咨询、设计、讲课等非雇佣收入，按次/按月预扣，汇算时并入综合所得，扣20%费用</p><ul><li>3️⃣ 稿酬</li></ul><p>文字创作：出书、发表文章、翻译等，同劳务报酬预扣，但汇算时收入额减按70%计算（打7折）</p><ul><li>4️⃣ 特许权使用费</li></ul><p>知识产权：专利、商标、著作权、非专利技术等授权收入，同劳务报酬预扣方式，汇算时并入综合所得（程序员卖代码、设计师卖模板、发明人授权专利等）,扣20%费用</p><blockquote><p>年度汇算就是把 <strong>这四类收入全年合并计算</strong>。</p></blockquote><h2 id="二、收入合计" tabindex="-1">二、收入合计 <a class="header-anchor" href="#二、收入合计" aria-label="Permalink to &quot;二、收入合计&quot;">​</a></h2><p><strong>收入合计 = 全年综合所得总收入</strong></p><p>包含：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>工资薪金</span></span>
<span class="line"><span>劳务报酬</span></span>
<span class="line"><span>稿酬</span></span>
<span class="line"><span>特许权使用费</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>工资收入      180000</span></span>
<span class="line"><span>劳务收入       20000</span></span>
<span class="line"><span>稿酬收入        5000</span></span>
<span class="line"><span>—————————————</span></span>
<span class="line"><span>收入合计      205000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>注意：</p><p>这是 <strong>税前收入</strong>。</p><h2 id="三、费用合计" tabindex="-1">三、费用合计 <a class="header-anchor" href="#三、费用合计" aria-label="Permalink to &quot;三、费用合计&quot;">​</a></h2><p><strong>费用合计</strong>主要指：</p><p>劳务报酬 / 稿酬 / 特许权使用费的 <strong>费用扣除比例</strong></p><p>税法规定：</p><table tabindex="0"><thead><tr><th>收入类型</th><th>扣除比例</th></tr></thead><tbody><tr><td>劳务报酬</td><td>20%</td></tr><tr><td>稿酬</td><td>20%（稿酬所得的收入额减按百分之七十计算。）</td></tr><tr><td>特许权使用费</td><td>20%</td></tr></tbody></table><p><strong>年度汇算时，劳务报酬、稿酬、特许权使用费所得如何计算收入额？</strong></p><p><strong>答：</strong> 劳务报酬所得、稿酬所得、特许权使用费所得以收入减除百分之二十的费用后的余额为收入额。稿酬所得的收入额减按百分之七十计算。</p><p><strong>举例：</strong> 居民个人小赵 2019 年取得工资收入 80000 元、劳务报酬收入 50000 元、特许权使用费收入 100000 元、稿酬收入 40000 元，请计算小赵 2019 年综合所得收入额是多少？</p><p><strong>所得收入额：</strong> 80000+（50000+100000）×（1-20%）+40000×（1-20%）×70%=222400（元）</p><p>参考网站：<a href="https://hainan.chinatax.gov.cn/gzcy_2_4/09124629.html" target="_blank" rel="noreferrer">中国个人所得税年度汇算申报明细计算方法</a></p><blockquote><p>工资薪金一般 <strong>没有这个费用扣除</strong>。</p></blockquote><h2 id="四、免税收入" tabindex="-1">四、免税收入 <a class="header-anchor" href="#四、免税收入" aria-label="Permalink to &quot;四、免税收入&quot;">​</a></h2><p><strong>免税收入 = 国家规定不用交税的收入</strong></p><p>常见包括：</p><ul><li>生育津贴</li><li>工伤补助</li><li>保险赔付</li><li>国家补贴</li><li>军人津贴</li></ul><p>例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>生育津贴 15000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>就会算在免税收入。</p><h2 id="五、减除费用" tabindex="-1">五、减除费用 <a class="header-anchor" href="#五、减除费用" aria-label="Permalink to &quot;五、减除费用&quot;">​</a></h2><p>这是 <strong>所有人都有的基础扣除</strong></p><p>中国个人所得税规定：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每人每年 60000 元</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>也就是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每月 5000</span></span>
<span class="line"><span>全年 60000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这个叫：</p><p><strong>基本减除费用</strong></p><h2 id="六、专项扣除合计" tabindex="-1">六、专项扣除合计 <a class="header-anchor" href="#六、专项扣除合计" aria-label="Permalink to &quot;六、专项扣除合计&quot;">​</a></h2><p>专项扣除是 <strong>五险一金</strong>。</p><p>包括：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>养老保险</span></span>
<span class="line"><span>医疗保险</span></span>
<span class="line"><span>失业保险</span></span>
<span class="line"><span>住房公积金</span></span>
<span class="line"><span>基本医疗保险</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>例如一年缴纳：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>养老保险      18000</span></span>
<span class="line"><span>医疗保险       5000</span></span>
<span class="line"><span>失业保险        800</span></span>
<span class="line"><span>公积金        20000</span></span>
<span class="line"><span>————————————</span></span>
<span class="line"><span>专项扣除合计  43800</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="七、专项附加扣除合计" tabindex="-1">七、专项附加扣除合计 <a class="header-anchor" href="#七、专项附加扣除合计" aria-label="Permalink to &quot;七、专项附加扣除合计&quot;">​</a></h2><p>这是国家鼓励政策，可以额外扣除。</p><p>主要包括：</p><table tabindex="0"><thead><tr><th>扣除项目</th><th>金额</th></tr></thead><tbody><tr><td>子女教育</td><td>1000/月</td></tr><tr><td>继续教育</td><td>400/月</td></tr><tr><td>住房贷款利息</td><td>1000/月</td></tr><tr><td>租房</td><td>800-1500/月</td></tr><tr><td>赡养老人</td><td>2000/月</td></tr><tr><td>3岁以下婴幼儿</td><td>2000/月</td></tr></tbody></table><p>例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>房贷利息 12000</span></span>
<span class="line"><span>赡养老人 24000</span></span>
<span class="line"><span>————————</span></span>
<span class="line"><span>专项附加扣除 36000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="八、其他扣除合计" tabindex="-1">八、其他扣除合计 <a class="header-anchor" href="#八、其他扣除合计" aria-label="Permalink to &quot;八、其他扣除合计&quot;">​</a></h2><p>这部分比较少见，例如：</p><ul><li>企业年金</li><li>职业年金</li><li>商业健康保险</li><li>税延养老保险</li></ul><p>例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>商业健康保险 2400</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="九、准予扣除的捐赠额" tabindex="-1">九、准予扣除的捐赠额 <a class="header-anchor" href="#九、准予扣除的捐赠额" aria-label="Permalink to &quot;九、准予扣除的捐赠额&quot;">​</a></h2><p>如果你向公益机构捐款，可以扣税。</p><p>但有比例限制：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>不超过应纳税所得额的 30%</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>公益捐款 5000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>可以在这里扣除。</p><h2 id="十、应纳税所得额" tabindex="-1">十、应纳税所得额 <a class="header-anchor" href="#十、应纳税所得额" aria-label="Permalink to &quot;十、应纳税所得额&quot;">​</a></h2><p>这是 <strong>最关键的一项</strong>。这是计算税的基础金额.</p><p>计算公式：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应纳税所得额</span></span>
<span class="line"><span>=</span></span>
<span class="line"><span>收入合计</span></span>
<span class="line"><span>- 费用合计</span></span>
<span class="line"><span>- 免税收入</span></span>
<span class="line"><span>- 减除费用</span></span>
<span class="line"><span>- 专项扣除</span></span>
<span class="line"><span>- 专项附加扣除</span></span>
<span class="line"><span>- 其他扣除</span></span>
<span class="line"><span>- 捐赠扣除</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>举个完整例子：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>收入合计           200000</span></span>
<span class="line"><span>费用合计            4000</span></span>
<span class="line"><span>免税收入               0</span></span>
<span class="line"><span>减除费用           60000</span></span>
<span class="line"><span>专项扣除           43800</span></span>
<span class="line"><span>专项附加扣除       36000</span></span>
<span class="line"><span>其他扣除            2400</span></span>
<span class="line"><span>捐赠扣除            5000</span></span>
<span class="line"><span>——————————————</span></span>
<span class="line"><span>应纳税所得额       48800</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>这个 <code>48800</code> 只是“计税基础”，还没算税。</p><h2 id="十一、应纳所得税额-应纳税额" tabindex="-1">十一、应纳所得税额(应纳税额) <a class="header-anchor" href="#十一、应纳所得税额-应纳税额" aria-label="Permalink to &quot;十一、应纳所得税额(应纳税额)&quot;">​</a></h2><p>根据 <strong>个人所得税税率表</strong>计算。</p><p>中国综合所得税率：</p><table tabindex="0"><thead><tr><th style="text-align:left;">级数</th><th style="text-align:left;">全年应纳税所得额</th><th style="text-align:left;">税率</th><th style="text-align:left;">速算扣除数</th></tr></thead><tbody><tr><td style="text-align:left;">1</td><td style="text-align:left;">不超过36,000元</td><td style="text-align:left;">3%</td><td style="text-align:left;">0</td></tr><tr><td style="text-align:left;">2</td><td style="text-align:left;">超过36,000至144,000元</td><td style="text-align:left;">10%</td><td style="text-align:left;">2,520</td></tr><tr><td style="text-align:left;">3</td><td style="text-align:left;">超过144,000至300,000元</td><td style="text-align:left;">20%</td><td style="text-align:left;">16,920</td></tr><tr><td style="text-align:left;">4</td><td style="text-align:left;">超过300,000至420,000元</td><td style="text-align:left;">25%</td><td style="text-align:left;">31,920</td></tr><tr><td style="text-align:left;">5</td><td style="text-align:left;">超过420,000至660,000元</td><td style="text-align:left;">30%</td><td style="text-align:left;">52,920</td></tr><tr><td style="text-align:left;">6</td><td style="text-align:left;">超过660,000至960,000元</td><td style="text-align:left;">35%</td><td style="text-align:left;">85,920</td></tr><tr><td style="text-align:left;">7</td><td style="text-align:left;">超过960,000元</td><td style="text-align:left;">45%</td><td style="text-align:left;">181,920</td></tr></tbody></table><p>计算公式：</p><div class="language-plain vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应纳税额 = 应纳税所得额 × 税率 − 速算扣除数</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应纳税所得额 80000</span></span>
<span class="line"><span>税率 10%</span></span>
<span class="line"><span>速算扣除数 2520</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>计算：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应纳税额 = 80000 × 10% - 2520</span></span>
<span class="line"><span>        = 5480</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这个 <code>5480</code> 就是应纳税额。需要上交给国家的钱。</p><h2 id="十二、减免税额" tabindex="-1">十二、减免税额 <a class="header-anchor" href="#十二、减免税额" aria-label="Permalink to &quot;十二、减免税额&quot;">​</a></h2><p>国家政策允许减免的税。</p><p>例如：</p><ul><li>残疾人减税</li><li>特殊人才政策</li><li>科研奖励</li></ul><p>普通人一般 <strong>为0</strong>。</p><h2 id="十三、已缴税额-全年已预缴的个人所得税" tabindex="-1">十三、已缴税额（全年已预缴的个人所得税） <a class="header-anchor" href="#十三、已缴税额-全年已预缴的个人所得税" aria-label="Permalink to &quot;十三、已缴税额（全年已预缴的个人所得税）&quot;">​</a></h2><p>这是公司 <strong>已经帮你预扣的税</strong>。 公司每月发工资时帮你代扣的个税。</p><p>例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1月 扣税 300</span></span>
<span class="line"><span>2月 扣税 350</span></span>
<span class="line"><span>3月 扣税 320</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>12月 扣税 400</span></span>
<span class="line"><span></span></span>
<span class="line"><span>全年：</span></span>
<span class="line"><span>已缴税额 = 4200</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>这些数据会自动同步到个人所得税APP。这个就叫 <strong>已缴税额</strong>。</p><p><strong>中国个税采用：预扣预缴制度</strong></p><p>意思是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每月先按估算扣税</span></span>
<span class="line"><span>年底再统一结算</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="每月计算公式" tabindex="-1">每月计算公式 <a class="header-anchor" href="#每月计算公式" aria-label="Permalink to &quot;每月计算公式&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当月应预缴税额 =</span></span>
<span class="line"><span>    (累计收入 - 累计扣除项) × 税率 - 速算扣除数</span></span>
<span class="line"><span>    - 之前月份已缴税额</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>关键步骤：</p><table tabindex="0"><thead><tr><th style="text-align:left;">步骤</th><th style="text-align:left;">操作</th></tr></thead><tbody><tr><td style="text-align:left;">1. 算累计</td><td style="text-align:left;">从1月到当月，收入逐月累加</td></tr><tr><td style="text-align:left;">2. 算扣除</td><td style="text-align:left;">5000元/月 + 三险一金 + 专项附加扣除，同样累计</td></tr><tr><td style="text-align:left;">3. 找税率</td><td style="text-align:left;">按累计应纳税所得额查税率表（3%-45%）</td></tr><tr><td style="text-align:left;">4. 算累计税</td><td style="text-align:left;">累计应纳税所得额 × 税率 - 速算扣除数</td></tr><tr><td style="text-align:left;">5. 减已缴</td><td style="text-align:left;">累计应缴税额 - 之前月份已缴 = 当月应缴</td></tr></tbody></table><h3 id="为什么会-跳档" tabindex="-1">为什么会&quot;跳档&quot;？ <a class="header-anchor" href="#为什么会-跳档" aria-label="Permalink to &quot;为什么会&quot;跳档&quot;？&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">阶段</th><th style="text-align:left;">累计应纳税所得额</th><th style="text-align:left;">税率</th><th style="text-align:left;">现象</th></tr></thead><tbody><tr><td style="text-align:left;">年初</td><td style="text-align:left;">0-36,000元</td><td style="text-align:left;">3%</td><td style="text-align:left;">每月个税较低且稳定</td></tr><tr><td style="text-align:left;">年中</td><td style="text-align:left;">超过36,000元</td><td style="text-align:left;">10%</td><td style="text-align:left;"><strong>当月个税突然增加</strong></td></tr><tr><td style="text-align:left;">下半年</td><td style="text-align:left;">超过144,000元</td><td style="text-align:left;">20%</td><td style="text-align:left;">继续跳档，税款更高</td></tr></tbody></table><p>本质：收入累计越多，超出部分适用更高税率，不是扣错了。</p><h3 id="全年流程图" tabindex="-1">全年流程图 <a class="header-anchor" href="#全年流程图" aria-label="Permalink to &quot;全年流程图&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1-12月 每月发薪</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 单位算累计收入</span></span>
<span class="line"><span>    ├── 算累计扣除（6万/年+三险一金+专项附加）</span></span>
<span class="line"><span>    ├── 查税率（可能跳档）</span></span>
<span class="line"><span>    ├── 扣当月个税</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>全年累计 = 已缴税额（系统会自动汇总）</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>次年3-6月 年度汇算</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 算全年实际应缴税额</span></span>
<span class="line"><span>    ├── 对比已缴税额</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 已缴 &gt; 应缴 → 退税</span></span>
<span class="line"><span>    ├── 已缴 &lt; 应缴 → 补税</span></span>
<span class="line"><span>    └── 已缴 = 应缴 → 不补不退</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><h2 id="十四、最终退税或补税" tabindex="-1">十四、最终退税或补税 <a class="header-anchor" href="#十四、最终退税或补税" aria-label="Permalink to &quot;十四、最终退税或补税&quot;">​</a></h2><p>最终计算：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应纳税额</span></span>
<span class="line"><span>- 减免税额</span></span>
<span class="line"><span>- 已缴税额</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>结果：</p><h3 id="情况1-多缴税" tabindex="-1">情况1：多缴税 <a class="header-anchor" href="#情况1-多缴税" aria-label="Permalink to &quot;情况1：多缴税&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应纳税额 4000</span></span>
<span class="line"><span>已缴税额 6000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>退税：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="情况2-少缴税" tabindex="-1">情况2：少缴税 <a class="header-anchor" href="#情况2-少缴税" aria-label="Permalink to &quot;情况2：少缴税&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应纳税额 6000</span></span>
<span class="line"><span>已缴税额 4000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>补税：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="十五、完整计算流程图" tabindex="-1">十五、完整计算流程图 <a class="header-anchor" href="#十五、完整计算流程图" aria-label="Permalink to &quot;十五、完整计算流程图&quot;">​</a></h2><p>整个年度汇算其实就是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>收入合计</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ├── 减：费用合计（劳务稿酬等20%）</span></span>
<span class="line"><span>   ├── 减：免税收入</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>应税收入</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ├── 减：减除费用（6万）</span></span>
<span class="line"><span>   ├── 减：专项扣除（三险一金）</span></span>
<span class="line"><span>   ├── 减：专项附加扣除（7项）</span></span>
<span class="line"><span>   ├── 减：其他扣除（年金等）</span></span>
<span class="line"><span>   ├── 减：准予扣除的捐赠额</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>应纳税所得额 ──→ 查税率表 ──→ 应纳所得额</span></span>
<span class="line"><span>   │                           │</span></span>
<span class="line"><span>   │                           ├── 减：减免税额</span></span>
<span class="line"><span>   │                           ├── 减：已缴税额（预扣预缴）</span></span>
<span class="line"><span>   │                           │</span></span>
<span class="line"><span>   │                           ▼</span></span>
<span class="line"><span>   │                       应退/补税额</span></span>
<span class="line"><span>   │                      （正数补税，负数退税）</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>年度汇算结果</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br></div></div><p>✅ <strong>一句话总结</strong></p><p>综合所得年度汇算就是：</p><p><strong>把全年收入统一计算，减去所有合法扣除，再和已缴税比较，决定退税还是补税。</strong></p>`,133))])}const k=p(b,[["render",o]]);export{f as __pageData,k as default};
